sub show_registration_form {
    my $q = shift;

    print $q->start_html('User Registration');
    print $q->h1('Register New User');

    print $q->start_form;
    print $q->p('Username: ' . $q->textfield(-name => 'username', -size => 30));
    print $q->p('Password: ' . $q->password_field(-name => 'password', -size => 30));
    print $q->p('Confirm Password: ' . $q->password_field(-name => 'confirm_password', -size => 30));
    print $q->p($q->submit(-value => 'Register User'));
    print $q->hidden(-name => 'action', -value => 'register');
    print $q->end_form;

    print $q->end_html;
}

sub handle_registration {
    my ($q, $user_file) = @_;

    my $username         = $q->param('username');
    my $password         = $q->param('password');
    my $confirm_password = $q->param('confirm_password');

    print $q->start_html('Registration Result');
    print $q->h1('Registration Result');

    # --- Input Validation ---
    unless (defined $username && length $username > 0) {
        print_error($q, 'Username cannot be empty.');
        print $q->end_html;
        return;
    }
    unless (defined $password && length $password > 0) {
        print_error($q, 'Password cannot be empty.');
        print $q->end_html;
        return;
    }
    unless ($password eq $confirm_password) {
        print_error($q, 'Passwords do not match.');
        print $q->end_html;
        return;
    }

    # --- Check for existing user ---
    my %users = read_user_database($user_file);
    if (exists $users{$username}) {
        print_error($q, "User '$username' already exists.");
        print $q->end_html;
        return;
    }

    # --- Hash Password ---
    # As per requirements, using md5_hex for backward compatibility.
    my $hashed_password = md5_hex($password);

    # --- Store User ---
    if (store_new_user($user_file, $username, $hashed_password)) {
        print $q->p("User '<b>$username</b>' registered successfully.");
        print $q->p("Hashed Password (MD5): <code>$hashed_password</code>"); # For demonstration
    } else {
        print_error($q, "Failed to store user '$username'. Check script permissions and file path ($user_file).");
    }

    print $q->end_html;
}

sub read_user_database {
    my $file = shift;
    my %users;

    return %users unless -e $file;

    # Open with exclusive lock for safety, then release
    open my $fh, '<', $file or die "Cannot open user database '$file' for reading: $!";
    flock $fh, 1; # shared lock
    while (my $line = <$fh>) {
        chomp $line;
        my ($user, $hash) = split /:/, $line, 2;
        $users{$user} = $hash;
    }
    flock $fh, 8; # unlock
    close $fh;

    return %users;
}

sub store_new_user {
    my ($file, $username, $hashed_password) = @_;

    # Open with exclusive lock for safety
    open my $fh, '>>', $file or return 0; # Append mode
    flock $fh, 2; # exclusive lock
    print $fh "$username:$hashed_password\n";
    flock $fh, 8; # unlock
    close $fh;

    return 1;
}

sub print_error {
    my ($q, $message) = @_;
